class Solution {
    int m;
    int topology(vector<int>&visited,vector<int>&node,vector<int>&indeg,int idx){
        int count=0;
        queue<int>q;
        // for(int i=0;i<m;i++){
        //     if(indeg[i]==0) q.push(i),visited[i]=1;
        // }
       q.push(idx);
        visited[idx]=1;
        while(!q.empty()){
            auto top=q.front();
            count++;
            q.pop();

                indeg[node[top]]--;
                if(indeg[node[top]]==0) {
                    visited[top]=1;
                    q.push(node[top]);
                }



        }

       return m-count;

    }
public:
    int longestCycle(vector<int>& favorite) {
        m=favorite.size();
        vector<int>indeg(m,0);
        for(int i=0;i<m;i++){
            if(favorite[i]==-1) continue;
            indeg[favorite[i]]++;

        }

        int ans=0;
        int c=0;

        vector<int>visited(m,0);
        for(int i=0;i<m;i++){
            if(favorite[i]==-1) continue;

            if(!indeg[i]&&!visited[i]){
                c++;
                ans=max(ans,topology(visited,favorite,indeg,i));
            }
        }
        return c==0?m:ans;
    }
};

