abhay: class Solution {
public:
    string findValidPair(const string& s) {
        vector<int> fre(10, 0);

        for (char c : s) {
            fre[c - '0']++;
        }

        for (size_t i = 0; i < s.length() - 1; i++) {
            if (s[i] != s[i + 1]) {
                int first_digit = s[i] - '0';
                int second_digit = s[i + 1] - '0';
                if (fre[first_digit] == first_digit && fre[second_digit] == second_digit) {
                    return s.substr(i, 2);
                }
            }
        }

        return "";
    }
};

text:
class Solution {
public:
    string findValidPair(const string& s) {
        vector<int> fre(10, 0);

        for (char c : s) {
            fre[c - '0']++;
        }

        for (size_t i = 0; i < s.length() - 1; i++) {
            if (s[i] != s[i + 1]) {
                int first_digit = s[i] - '0';
                int second_digit = s[i + 1] - '0';
                if (fre[first_digit] == first_digit && fre[second_digit] == second_digit) {
                    return s.substr(i, 2);
                }
            }
        }

        return "";
    }
};

