        for (int i=0;i<26;i++){
            if (arr[i] and (ans.empty() or ans.back()!=i+'A')){
                ans+=i+'A';
                arr[i]--;
                break;

            }
        }
    }

    maxi=*max_element(arr.begin(),arr.end());
    int idx=0;
    while (arr[idx]!=maxi) idx++;
    while (ans.size()!=n){
        ans+=idx+'A';
        for (int i=0;i<26;i++){
            if (i==idx) continue;
            if (arr[i] and (ans.empty() or ans.back()!=i+'A')){
                ans+=i+'A';
                arr[i]--;
                break;

            }
        }
    }

